<template><aside class="metrics-panel"><header><h3>因子结果</h3><span>{{ factors.length }}</span></header><div v-if="metrics.length" class="metric-grid"><div v-for="item in metrics.slice(0,8)" :key="item.label"><small>{{ item.label }}</small><strong :class="item.tone">{{ item.percent&&item.rawValue!=null?`${(Math.abs(item.rawValue)*100).toFixed(2)}%`:item.rawValue!=null?item.rawValue.toFixed(4):item.value }}</strong></div></div><article v-if="hypothesis"><small>研究假设</small><p>{{ hypothesisText }}</p></article><article v-if="feedbackText"><small>反馈摘要</small><p>{{ feedbackText }}</p></article><el-button v-if="hasData" class="export-button" @click="$emit('download')">导出当前结果</el-button></aside></template>
<script setup lang="ts">import { computed } from 'vue'; import type { FactorItem,FeedbackSummary,MetricItem } from '../types'; const props=defineProps<{metrics:MetricItem[];factors:FactorItem[];hypothesis:Record<string,unknown>|null;feedback:FeedbackSummary}>(); defineEmits<{download:[]}>(); const hypothesisText=computed(()=>String(props.hypothesis?.hypothesis||props.hypothesis?.concise_observation||'')); const hasData=computed(()=>props.metrics.length||props.factors.length||props.feedback.reason);const feedbackText=computed(()=>props.feedback.reason||props.feedback.observations||props.feedback.evaluation)</script>
